<?php
if(!defined("IN_ESOTALK"))exit;class skins extends Controller{var $view="skins.view.php";var $skins=array();function init(){if(!$this->esoTalk->user["admin"])redirect("");global $language,$config;$this->title=$language["Skins"];if(isset($_FILES["installSkin"]) and $this->esoTalk->validateToken(@$_POST["token"]))$this->installSkin();if($handle=opendir("skins")){while(false!==($file=readdir($handle))){if($file[0]!="." and is_dir("skins/$file") and file_exists("skins/$file/skin.php") and (include_once "skins/$file/skin.php") and class_exists($file)){$skin=new $file;if(file_exists("skins/$file/preview.jpg"))$preview="preview.jpg";elseif(file_exists("skins/$file/preview.png"))$preview="preview.png";elseif(file_exists("skins/$file/preview.gif"))$preview="preview.gif";else $preview="";$this->skins[$file]=array("selected"=>$config["skin"]==$file,"name"=>$skin->name,"version"=>$skin->version,"author"=>$skin->author,"preview"=>$preview);}}closedir($handle);}ksort($this->skins);if(!empty($_GET["q2"]) and $this->esoTalk->validateToken(@$_GET["token"]))$this->changeSkin($_GET["q2"]);}function changeSkin($skin){if(!array_key_exists($skin,$this->skins))return false;writeConfigFile("config/skin.php",'$config["skin"]',$skin);redirect("skins");}function installSkin(){if($_FILES["installSkin"]["error"]){$this->esoTalk->message("invalidSkin");return false;}if(!move_uploaded_file($_FILES["installSkin"]["tmp_name"],"skins/{$_FILES["installSkin"]["name"]}")){$this->esoTalk->message("notWritable",false,"skins/");return false;}if(!($files=unzip("skins/{$_FILES["installSkin"]["name"]}","skins/")))$this->esoTalk->message("invalidSkin");else {$directories=0;$skinFound=false;foreach($files as $k=>$file){if(substr($file["name"],0,9)=="__MACOSX/" or substr($file["name"],-9)==".DS_Store"){unset($files[$k]);continue;}if($file["directory"] and substr_count($file["name"],"/")<2)$directories++;if(substr($file["name"],-8)=="skin.php")$skinFound=true;}if($skinFound and $directories==1){$error=false;foreach($files as $k=>$file){if($file["directory"] and !is_dir("skins/{$file["name"]}"))mkdir("skins/{$file["name"]}");elseif(!$file["directory"]){if(!writeFile("skins/{$file["name"]}",$file["content"])){$this->esoTalk->message("notWritable",false,"skins/{$file["name"]}");$error=true;break;}}}if(!$error)$this->esoTalk->message("skinAdded");}else $this->esoTalk->message("invalidSkin");}unlink("skins/{$_FILES["installSkin"]["name"]}");}}?>
